"""xAI provider — model listing and chat completion with vision support."""from __future__ import annotationsimport jsonfrom ...errors import LLMProviderResponseErrorfrom ...interfaces.provider_client import BaseProviderClientfrom ...schemas.chat import (    LLM_CHAT_FINISH_CONTENT_FILTER,    LLM_CHAT_FINISH_LENGTH,    LLM_CHAT_FINISH_STOP,    LLMChatMessage,    LLMChatMessageImage,    LLMChatMessageText,    LLMChatReasoningEffort,    LLMChatRequest,    LLMChatResponse,    LLMChatRole,)from ...schemas.models import LLMModelInfo, LLMModelsRequest, LLMModelsResponse# Только эти модели принимают reasoning_effort_REASONING_EFFORT_MODELS = {    "grok-3-mini",    "grok-3-mini-beta",    "grok-3-mini-fast",}# Только эти возвращают reasoning_content в Chat Completions_REASONING_CONTENT_MODELS = {    "grok-3-mini",    "grok-3-mini-beta",    "grok-3-mini-fast",}def _extract_model_id(item: dict) -> str:    for key in ("id", "name", "model", "model_id", "modelName"):        value = item.get(key)        if value is None:            continue        model_id = str(value).strip()        if model_id:            return model_id    return ""def _has_image_modality(item: dict) -> bool:    for key in ("input_modalities", "output_modalities"):        arr = item.get(key)        if isinstance(arr, list) and "image" in arr:            return True    return Falsedef _get_created(item: dict) -> int:    v = item.get("created")    if isinstance(v, (int, float)):        return int(v)    return 0class XAIProvider(BaseProviderClient):    PROVIDER_CODE = "xai"    BASE_URL = "https://api.x.ai"    ROLE_MAP = {        LLMChatRole.SYSTEM: LLMChatRole.SYSTEM.value,        LLMChatRole.USER: LLMChatRole.USER.value,        LLMChatRole.ASSISTANT: LLMChatRole.ASSISTANT.value,    }    REASONING_EFFORT_MAP = {        LLMChatReasoningEffort.LOW: "low",        LLMChatReasoningEffort.MEDIUM: "high",        LLMChatReasoningEffort.HIGH: "high",    }    FINISH_REASON_MAP = {        LLM_CHAT_FINISH_STOP: LLM_CHAT_FINISH_STOP,        LLM_CHAT_FINISH_LENGTH: LLM_CHAT_FINISH_LENGTH,        LLM_CHAT_FINISH_CONTENT_FILTER: LLM_CHAT_FINISH_CONTENT_FILTER,    }    def _build_headers(self) -> dict[str, str]:        key = (self._config.xai_api_key or "").strip()        return {"Authorization": f"Bearer {key}"}    def parse_error_message(self, status_code: int, body_raw: str) -> str | None:        # xAI: {"code": "Client specified an invalid argument", "error": "Incorrect API key provided: ..."} — error is string        try:            data = json.loads(body_raw) if body_raw.strip() else {}        except (json.JSONDecodeError, TypeError):            return None        if not isinstance(data, dict):            return None        err = data.get("error")        if isinstance(err, dict) and err.get("message"):            return str(err["message"]).strip() or None        if isinstance(err, str) and err.strip():            msg = err.strip()            code = (data.get("code") or "").strip() if isinstance(data.get("code"), str) else ""            return f"{code}: {msg}" if code else msg        return None    def _fetch_models(self) -> list[dict]:        if not (self._config.xai_api_key or "").strip():            return []        data = self._send_get_request("/v1/models")        raw = data.get("data") if isinstance(data, dict) else None        if not isinstance(raw, list):            return []        return [item for item in raw if isinstance(item, dict)]    def _fetch_language_models(self) -> list[dict]:        if not (self._config.xai_api_key or "").strip():            return []        data = self._send_get_request("/v1/language-models")        raw = data.get("models") if isinstance(data, dict) else None        if not isinstance(raw, list):            return []        return [item for item in raw if isinstance(item, dict)]    def models(self, request: LLMModelsRequest) -> LLMModelsResponse:        by_code: dict[str, LLMModelInfo] = {}        for item in self._fetch_models():            mid = _extract_model_id(item)            if not mid:                continue            by_code[mid] = LLMModelInfo(                provider=self.provider_code,                model=mid,                created=_get_created(item),            )        for item in self._fetch_language_models():            mid = _extract_model_id(item)            if not mid:                continue            created = _get_created(item)            if mid in by_code:                old = by_code[mid]                by_code[mid] = LLMModelInfo(                    provider=old.provider,                    model=old.model,                    created=old.created or created,                )            else:                by_code[mid] = LLMModelInfo(                    provider=self.provider_code,                    model=mid,                    created=created,                )        return LLMModelsResponse(provider=self.provider_code, models=tuple(by_code.values()))    def _build_message_content(        self, content: list[LLMChatMessageText | LLMChatMessageImage]    ) -> str | list[dict]:        """        Convert internal message content list to xAI API format.        Returns a plain string if only text, or a list of content objects for multimodal.        """        if all(isinstance(c, LLMChatMessageText) for c in content):            return "".join(c.message for c in content)        parts: list[dict] = []        for item in content:            if isinstance(item, LLMChatMessageText):                parts.append({"type": "text", "text": item.message})            elif isinstance(item, LLMChatMessageImage):                parts.append({                    "type": "image_url",                    "image_url": {                        "url": f"data:{item.mime};base64,{item.base64}",                        "detail": "auto",                    },                })        return parts    def _serialize_messages(self, messages: list[LLMChatMessage]) -> list[dict]:        """Convert internal LLMChatMessage list to xAI API messages format."""        result = []        for msg in messages:            result.append({                "role": self._map_role(msg.role),                "content": self._build_message_content(msg.content),            })        return result    def _parse_chat_response(self, data: dict, request: LLMChatRequest) -> LLMChatResponse:        """Parse xAI /v1/chat/completions response into LLMChatResponse."""        choices = data.get("choices") or []        if not choices:            raise LLMProviderResponseError(                f"xAI response contains no choices; raw: {self._serialize_log_body(data)}"            )        choice = choices[0]        raw_msg = choice.get("message") or {}        content_str = raw_msg.get("content") or ""        reasoning_str = ""        if request.model in _REASONING_CONTENT_MODELS:            reasoning_str = raw_msg.get("reasoning_content") or ""        finish_reason = self._normalize_finish_reason(choice.get("finish_reason"))        message = LLMChatMessage(            role=LLMChatRole.ASSISTANT,            content=[LLMChatMessageText(message=content_str)],        )        raw_usage = data.get("usage")        tokens_usage = None        if isinstance(raw_usage, dict):            tokens_usage = self._create_tokens_usage(                prompt=raw_usage.get("prompt_tokens", 0),                reasoning=0,                completion=raw_usage.get("completion_tokens", 0),                total=raw_usage.get("total_tokens", 0),            )        return LLMChatResponse(            response_id=data.get("id"),            message=message,            finish_reason=finish_reason,            created=data.get("created", 0),            tokens_usage=tokens_usage,            message_reasoning=reasoning_str,        )    def chat(self, request: LLMChatRequest, *, cache: bool = False) -> LLMChatResponse:        """        Send a chat completion request to xAI /v1/chat/completions.        cache is accepted for interface compatibility but not used at provider level.        """        body: dict = {            "model": request.model,            "messages": self._serialize_messages(request.messages),            "max_tokens": request.max_tokens,            "stream": False,        }        if request.temperature is not None:            body["temperature"] = request.temperature        if request.top_p is not None:            body["top_p"] = request.top_p        reasoning_effort = self._map_reasoning_effort(request.reasoning)        if (            reasoning_effort is not None            and request.model in _REASONING_EFFORT_MODELS        ):            body["reasoning_effort"] = reasoning_effort        data = self._send_post_request(            "/v1/chat/completions",            body,            endpoint_name="chat/completions",        )        return self._parse_chat_response(data, request)